import React, { useMemo } from 'react';
import { useApp } from '../context/AppContext';
import { CATEGORY_COLORS } from '../data/transactions';
import { formatINR } from '../utils';
import { monthlyBalanceData } from '../data/transactions';

export default function Insights() {
  const { transactions } = useApp();

  const analysis = useMemo(() => {
    const expenses = transactions.filter(t => t.type === 'expense');
    const income = transactions.filter(t => t.type === 'income');

    // Category breakdown
    const catMap = {};
    expenses.forEach(t => { catMap[t.category] = (catMap[t.category] || 0) + t.amount; });
    const catList = Object.entries(catMap).sort((a, b) => b[1] - a[1]);
    const topCat = catList[0];
    const totalExpense = expenses.reduce((s, t) => s + t.amount, 0);
    const totalIncome = income.reduce((s, t) => s + t.amount, 0);

    // Savings rate
    const savingsRate = totalIncome > 0 ? ((totalIncome - totalExpense) / totalIncome * 100).toFixed(1) : 0;

    // Most frequent category
    const freqMap = {};
    expenses.forEach(t => { freqMap[t.category] = (freqMap[t.category] || 0) + 1; });
    const freqCat = Object.entries(freqMap).sort((a, b) => b[1] - a[1])[0];

    return { catList, topCat, totalExpense, totalIncome, savingsRate, freqCat };
  }, [transactions]);

  const maxBar = analysis.catList[0]?.[1] || 1;
  const maxMonth = Math.max(...monthlyBalanceData.flatMap(d => [d.income, d.expenses]));

  if (transactions.length === 0) {
    return (
      <div className="empty-state" style={{ marginTop: 80 }}>
        <div className="empty-icon">📊</div>
        <p>No data to generate insights yet. Add some transactions first.</p>
      </div>
    );
  }

  return (
    <div className="insights-grid">

      {/* Top Spending Category */}
      <div className="insight-card">
        <div className="insight-title"><span>🔥</span> Top Spending Category</div>
        {analysis.topCat ? (
          <>
            <div className="insight-big" style={{ color: CATEGORY_COLORS[analysis.topCat[0]] || 'var(--accent)' }}>
              {analysis.topCat[0]}
            </div>
            <div className="insight-sub" style={{ marginBottom: 20 }}>
              {formatINR(analysis.topCat[1])} · {((analysis.topCat[1] / analysis.totalExpense) * 100).toFixed(1)}% of expenses
            </div>
            <div>
              {analysis.catList.slice(0, 5).map(([cat, val]) => (
                <div className="bar-row" key={cat}>
                  <div className="bar-label">{cat}</div>
                  <div className="bar-track">
                    <div className="bar-fill" style={{
                      width: `${(val / maxBar) * 100}%`,
                      background: CATEGORY_COLORS[cat] || 'var(--accent)',
                    }} />
                  </div>
                  <div className="bar-val">{formatINR(val)}</div>
                </div>
              ))}
            </div>
          </>
        ) : <div className="insight-sub">No expense data</div>}
      </div>

      {/* Savings Rate */}
      <div className="insight-card">
        <div className="insight-title"><span>💰</span> Savings Rate</div>
        <div className="insight-big" style={{ color: Number(analysis.savingsRate) >= 20 ? 'var(--green)' : 'var(--red)' }}>
          {analysis.savingsRate}%
        </div>
        <div className="insight-sub" style={{ marginBottom: 20 }}>
          {Number(analysis.savingsRate) >= 20
            ? '✓ Great savings discipline!'
            : '⚠ Consider reducing expenses'}
        </div>
        <div className="bar-row">
          <div className="bar-label">Saved</div>
          <div className="bar-track">
            <div className="bar-fill" style={{ width: `${analysis.savingsRate}%`, background: 'var(--green)' }} />
          </div>
          <div className="bar-val">{analysis.savingsRate}%</div>
        </div>
        <div className="bar-row">
          <div className="bar-label">Spent</div>
          <div className="bar-track">
            <div className="bar-fill" style={{ width: `${100 - analysis.savingsRate}%`, background: 'var(--red)' }} />
          </div>
          <div className="bar-val">{(100 - analysis.savingsRate).toFixed(1)}%</div>
        </div>
        <div style={{ marginTop: 16, padding: '12px 14px', background: 'var(--bg-elevated)', borderRadius: 10, fontSize: '0.78rem', color: 'var(--text-secondary)' }}>
          Total Income: {formatINR(analysis.totalIncome)}<br />
          Total Expenses: {formatINR(analysis.totalExpense)}
        </div>
      </div>

      {/* Monthly Comparison */}
      <div className="insight-card">
        <div className="insight-title"><span>📅</span> Monthly Comparison</div>
        <div className="month-compare-row">
          {monthlyBalanceData.map(m => (
            <div className="month-col" key={m.month}>
              <div className="month-name">{m.month}</div>
              <div className="month-bar-wrap">
                <div className="month-bar income"
                  style={{ height: `${(m.income / maxMonth) * 80}px` }}
                  title={`Income: ${formatINR(m.income)}`} />
                <div className="month-bar expense"
                  style={{ height: `${(m.expenses / maxMonth) * 80}px` }}
                  title={`Expenses: ${formatINR(m.expenses)}`} />
              </div>
              <div className="month-total">
                <span style={{ color: 'var(--green)' }}>+{(m.income / 1000).toFixed(0)}K</span>
                {' / '}
                <span style={{ color: 'var(--red)' }}>{(m.expenses / 1000).toFixed(0)}K</span>
              </div>
            </div>
          ))}
        </div>
        <div style={{ marginTop: 16, display: 'flex', gap: 16, fontSize: '0.75rem', color: 'var(--text-muted)' }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
            <div style={{ width: 10, height: 10, background: 'var(--green)', borderRadius: 2 }} /> Income
          </div>
          <div style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
            <div style={{ width: 10, height: 10, background: 'var(--red)', borderRadius: 2 }} /> Expenses
          </div>
        </div>
      </div>

      {/* Most Frequent Category */}
      <div className="insight-card">
        <div className="insight-title"><span>📌</span> Most Active Category</div>
        {analysis.freqCat ? (
          <>
            <div className="insight-big" style={{ color: CATEGORY_COLORS[analysis.freqCat[0]] || 'var(--blue)' }}>
              {analysis.freqCat[0]}
            </div>
            <div className="insight-sub" style={{ marginBottom: 20 }}>
              {analysis.freqCat[1]} transactions recorded
            </div>
          </>
        ) : null}

        <div style={{ background: 'var(--bg-elevated)', borderRadius: 12, padding: '14px 16px' }}>
          <div style={{ fontSize: '0.72rem', fontWeight: 600, color: 'var(--text-muted)', letterSpacing: '0.08em', textTransform: 'uppercase', marginBottom: 12 }}>
            Key Observations
          </div>
          {[
            `Housing takes a fixed ${formatINR(15000)}/month commitment.`,
            `Freelance income supplements your primary salary well.`,
            `Investment income adds passive revenue each month.`,
            `Travel & Entertainment are discretionary — easy to reduce.`,
          ].map((obs, i) => (
            <div key={i} style={{ display: 'flex', gap: 10, marginBottom: 10, fontSize: '0.8rem', color: 'var(--text-secondary)', alignItems: 'flex-start' }}>
              <span style={{ color: 'var(--accent)', flexShrink: 0 }}>◆</span>
              {obs}
            </div>
          ))}
        </div>
      </div>

    </div>
  );
}
